class Solution:
    def findRadius(self, houses, heaters):
        # Naive: for each house scan every heater for the closest one.
        ans = 0
        for h in houses:
            nearest = min(abs(h - x) for x in heaters)
            if nearest > ans:
                ans = nearest
        return ans

