import bisect

class Solution:
    def findRadius(self, houses, heaters):
        heaters = sorted(heaters)
        ans = 0
        for h in houses:
            i = bisect.bisect_left(heaters, h)
            best = float('inf')
            if i < len(heaters):
                best = min(best, heaters[i] - h)
            if i > 0:
                best = min(best, h - heaters[i - 1])
            if best > ans:
                ans = best
        return ans

