var findRadius = function(houses, heaters) {
    heaters.sort((a, b) => a - b);
    const m = heaters.length;
    let ans = 0;
    for (const h of houses) {
        let lo = 0, hi = m;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (heaters[mid] < h) lo = mid + 1;
            else hi = mid;
        }
        let best = Infinity;
        if (lo < m) best = Math.min(best, heaters[lo] - h);
        if (lo > 0) best = Math.min(best, h - heaters[lo - 1]);
        if (best > ans) ans = best;
    }
    return ans;
};
